const webhook = $input.item.json.body || $input.item.json;

// Validate input structure
if (!webhook || !webhook.data) {
  return {
    json: {
      success: false,
      error: 'VALIDATION_ERROR: Missing data object in webhook payload',
      validation_failed: true,
      route_decision: 'skip_crm',
      timestamp: new Date().toISOString()
    }
  };
}

const data = webhook.data;
const clientData = data.conversation_initiation_client_data || {};
const dynamicVars = clientData.dynamic_variables || {};
const analysis = data.analysis || {};

let qualificationStatus = 'unknown';
let qualificationScore = 0;

if (analysis.call_successful === 'success') {
  qualificationStatus = 'qualified';
  qualificationScore = 80;
} else if (analysis.call_successful === 'failure') {
  qualificationStatus = 'not_qualified';
  qualificationScore = 20;
} else {
  qualificationStatus = 'needs_review';
  qualificationScore = 50;
}

const collectedData = analysis.data_collection_results || {};

// Handle both string and number pipedrive_person_id
let personId = dynamicVars.pipedrive_person_id;
if (typeof personId === 'string') {
  personId = parseInt(personId, 10);
}
const validPersonId = (typeof personId === 'number' && !isNaN(personId) && personId > 0) ? personId : 0;
const routeDecision = validPersonId > 0 ? 'update_crm' : 'skip_crm';

const result = {
  pipedrive_person_id: validPersonId,
  route_decision: routeDecision,
  customer_name: dynamicVars.customer_name || '',
  customer_phone: dynamicVars.phone || '',
  conversation_id: data.conversation_id || 'unknown',
  agent_id: data.agent_id || 'unknown',
  call_duration_secs: data.metadata?.call_duration_secs || 0,
  call_timestamp: data.metadata?.start_time_unix_secs || 0,
  qualification_status: qualificationStatus,
  qualification_score: qualificationScore,
  call_successful: analysis.call_successful || 'unknown',
  transcript_summary: analysis.transcript_summary || '',
  collected_data: collectedData,
  budget: collectedData.budget || 'not_discussed',
  timeline: collectedData.timeline || 'not_discussed',
  authority: collectedData.authority || 'not_discussed',
  need: collectedData.need || 'not_discussed',
  transcript: data.transcript || [],
  transcript_text: (data.transcript || []).map(t => `${t.role}: ${t.message}`).join('\n'),
  event_timestamp: webhook.event_timestamp || Date.now()
};

return { json: result };

