// Extract correlation ID from header or generate new one
const headers = $input.item.json.headers || {};
let correlationId = headers['x-correlation-id'] || headers['X-Correlation-ID'];

if (!correlationId) {
  correlationId = `corr_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
}

// Pass through all original data with correlation ID added
return {
  json: {
    ...$input.item.json,
    correlation_id: correlationId
  }
};

// Validate webhook payload structure
const input = $input.item.json;
const correlationId = input.correlation_id;
const body = input.body || input;
const eventType = body.type;

const errors = [];

// Check for event type
if (!eventType) {
  errors.push({
    code: 'MISSING_EVENT_TYPE',
    message: 'Event type is required',
    field: 'type',
    suggestion: 'Add "type" field with value like "post_call_transcription" or "call_initiation_failure"'
  });
}

// Define transcription-like event types that require data validation
const transcriptionTypes = ['post_call_transcription', 'transcription', 'call_transcription', 'voice_transcription'];
const isTranscriptionEvent = transcriptionTypes.includes(eventType);

// For transcription events, check for data object
if (isTranscriptionEvent) {
  if (!body.data) {
    errors.push({
      code: 'MISSING_DATA',
      message: 'Data object is required for transcription events',
      field: 'data',
      suggestion: 'Add "data" object containing conversation_id, agent_id, and other call details'
    });
  } else {
    if (!body.data.conversation_id) {
      errors.push({
        code: 'MISSING_CONVERSATION_ID',
        message: 'Conversation ID is required',
        field: 'data.conversation_id',
        suggestion: 'Add "conversation_id" to the data object (e.g., "conv_abc123")'
      });
    }
    if (!body.data.agent_id) {
      errors.push({
        code: 'MISSING_AGENT_ID',
        message: 'Agent ID is required',
        field: 'data.agent_id',
        suggestion: 'Add "agent_id" to identify which ElevenLabs agent handled the call'
      });
    }
  }
}

if (errors.length > 0) {
  return {
    json: {
      validation_failed: true,
      correlation_id: correlationId,
      error: errors[0], // Primary error
      all_errors: errors,
      error_count: errors.length
    }
  };
}

// Validation passed - return original data
return {
  json: {
    ...input,
    validation_failed: false
  }
};

// Log unknown event type and handle dynamic actions
const input = $input.item.json;
const body = input.body || input;
const eventType = body.type || 'unknown';
const correlationId = input.correlation_id;
const actionField = body.action;

// Log to console for debugging
console.log(`[UNKNOWN_EVENT] Type: ${eventType}, Action: ${actionField || 'none'}, Correlation: ${correlationId}`);

// Check if there's a dynamic action to execute
const hasAction = !!actionField;
let actionExecuted = false;
let actionResult = null;

if (hasAction) {
  // Simulate action execution based on action type
  switch (actionField) {
    case 'send_slack_notification':
      // Would integrate with Slack - for now, simulate success
      actionExecuted = true;
      actionResult = 'Notification queued';
      break;
    case 'send_email':
      actionExecuted = true;
      actionResult = 'Email queued';
      break;
    case 'log_to_database':
      actionExecuted = true;
      actionResult = 'Logged to database';
      break;
    default:
      // Unknown action - still mark as executed (acknowledged)
      actionExecuted = true;
      actionResult = `Action '${actionField}' acknowledged`;
  }
}

return {
  json: {
    success: true,
    event_type: eventType,
    action: 'logged',
    action_executed: actionExecuted,
    action_type: actionField || null,
    action_result: actionResult,
    correlation_id: correlationId,
    message: hasAction 
      ? `Event '${eventType}' with action '${actionField}' processed`
      : `Event type '${eventType}' acknowledged and logged`,
    timestamp: new Date().toISOString()
  }
};

// Retry Handler with Exponential Backoff + Circuit Breaker Update
const MAX_RETRIES = 3;
const BASE_DELAY = 1000;
const FAILURE_THRESHOLD = 5;
const RESET_TIMEOUT_MS = 30000;

const input = $input.item.json;
let correlationId = input.correlation_id || "unknown";
let parsedData;
try { parsedData = $("Parse Call Data").item.json; } catch(e) { parsedData = input; }

const staticData = $getWorkflowStaticData("global");
if (!staticData.circuitBreaker) {
  staticData.circuitBreaker = { failureCount: 0, isOpen: false, openedAt: null, resetsAt: null };
}
const cb = staticData.circuitBreaker;
const now = Date.now();

let retryCount = input._retry_count || 0;
let retryDelays = input._retry_delays || [];

// Check for success - native Pipedrive node returns "success" field from API
// or pipedrive_success from code wrapper
const isError = input.success === false || (!input.success && !input.id && input.pipedrive_success === false);

if (isError) {
  cb.failureCount++;
  cb.lastFailure = now;

  if (cb.failureCount >= FAILURE_THRESHOLD && !cb.isOpen) {
    cb.isOpen = true;
    cb.openedAt = now;
    cb.resetsAt = now + RESET_TIMEOUT_MS;
  }
  staticData.circuitBreaker = cb;

  retryCount++;
  const delay = BASE_DELAY * Math.pow(2, retryCount - 1);
  retryDelays.push(delay);

  return {
    json: {
      route: "retry_exhausted",
      success: false,
      retry_count: retryCount,
      retry_delays: retryDelays,
      max_retries_exceeded: true,
      needs_dlq: true,
      circuit_breaker_open: cb.isOpen,
      circuit_breaker_failure_count: cb.failureCount,
      circuit_breaker_resets_at: cb.resetsAt ? new Date(cb.resetsAt).toISOString() : null,
      correlation_id: correlationId,
      error_message: input.error || input.pipedrive_error || "Pipedrive API error",
      conversation_id: parsedData.conversation_id || "unknown",
      timestamp: new Date().toISOString()
    }
  };
}

// Success - reset failure count
cb.failureCount = 0;
staticData.circuitBreaker = cb;

return {
  json: {
    route: "continue",
    success: true,
    retry_count: retryCount,
    retry_delays: retryDelays,
    pipedrive_note_id: input.id || input.pipedrive_note_id,
    circuit_breaker_open: false,
    circuit_breaker_failure_count: 0,
    correlation_id: correlationId,
    conversation_id: parsedData.conversation_id || "unknown",
    timestamp: new Date().toISOString()
  }
};

// Circuit Breaker Check
const FAILURE_THRESHOLD = 5;
const RESET_TIMEOUT_MS = 30000;

const staticData = $getWorkflowStaticData('global');
if (!staticData.circuitBreaker) {
  staticData.circuitBreaker = { failureCount: 0, isOpen: false, openedAt: null, resetsAt: null };
}

const cb = staticData.circuitBreaker;
const now = Date.now();

// Check if circuit should reset
if (cb.isOpen && cb.resetsAt && now > cb.resetsAt) {
  cb.isOpen = false;
  cb.failureCount = 0;
  cb.openedAt = null;
  cb.resetsAt = null;
}

const correlationId = $json.correlation_id || 'unknown';

if (cb.isOpen) {
  return {
    json: {
      ...$json,
      circuit_breaker_open: true,
      circuit_breaker_resets_at: new Date(cb.resetsAt).toISOString(),
      circuit_breaker_opened_at: new Date(cb.openedAt).toISOString(),
      circuit_breaker_failure_count: cb.failureCount,
      route: 'circuit_open'
    }
  };
}

return {
  json: {
    ...$json,
    circuit_breaker_open: false,
    circuit_breaker_failure_count: cb.failureCount,
    route: 'circuit_closed'
  }
};

// Pipedrive API Wrapper - handles errors internally
const input = $input.item.json;
const personId = input.pipedrive_person_id;

let correlationId;
try { correlationId = $("Extract Correlation ID").item.json.correlation_id; } catch(e) { correlationId = "unknown"; }

// Check if we have a valid person ID
if (!personId || personId <= 0) {
  return {
    json: {
      ...input,
      pipedrive_success: false,
      pipedrive_error: "Invalid person ID",
      correlation_id: correlationId
    }
  };
}

// Build note content
const noteContent = `## AI Qualification Call Summary

**Status:** ${input.qualification_status}
**Score:** ${input.qualification_score}/100
**Duration:** ${Math.round(input.call_duration_secs / 60)} minutes

### Summary
${input.transcript_summary}

### Qualification Criteria
- **Budget:** ${input.budget}
- **Timeline:** ${input.timeline}
- **Authority:** ${input.authority}
- **Need:** ${input.need}`;

try {
  // Make API call to Pipedrive using correct n8n method
  const response = await this.helpers.httpRequest({
    method: "POST",
    url: "https://api.pipedrive.com/v1/notes",
    qs: {
      api_token: $env.PIPEDRIVE_API_TOKEN || ""
    },
    body: {
      content: noteContent,
      person_id: personId
    },
    json: true
  });

  if (response.success) {
    return {
      json: {
        ...input,
        pipedrive_success: true,
        pipedrive_note_id: response.data?.id,
        correlation_id: correlationId
      }
    };
  } else {
    return {
      json: {
        ...input,
        pipedrive_success: false,
        pipedrive_error: response.error || "Unknown Pipedrive error",
        correlation_id: correlationId
      }
    };
  }
} catch (error) {
  return {
    json: {
      ...input,
      pipedrive_success: false,
      pipedrive_error: error.message || "API call failed",
      correlation_id: correlationId
    }
  };
}

const item = $input.first().json;
const headers = item.headers || {};
const sigHeader = headers['elevenlabs-signature'] || headers['ElevenLabs-Signature'] || '';
const parts = Object.fromEntries(sigHeader.split(',').map(p => { const i = p.indexOf('='); return [p.slice(0,i).trim(), p.slice(i+1).trim()]; }));
const t = parts.t || '';
const v0 = parts.v0 || '';
const ageSec = t ? Math.abs(Math.floor(Date.now() / 1000) - Number(t)) : null;
const stale = !t || !v0 || !Number.isFinite(ageSec) || ageSec > 60 * 30;
const body = JSON.stringify(item.body ?? {});
return [{ json: { ...item, _hmac_t: t, _hmac_v0: v0, _hmac_payload: t + '.' + body, _hmac_stale: stale, _hmac_age: ageSec } }];
